// Parse the Stripe event from the webhook body
const raw = $input.first().json;
const event = raw.body ?? raw;

const eventType = event.type;
const data = event.data?.object ?? {};

// Extract relevant fields based on event type
let organizationId = null;
let stripeCustomerId = null;
let stripeSubscriptionId = null;
let stripePriceId = null;
let status = null;
let billingCycle = null;
let currentPeriodStart = null;
let currentPeriodEnd = null;
let planId = null;

if (eventType === 'checkout.session.completed') {
  organizationId = data.metadata?.organization_id ?? data.client_reference_id;
  stripeCustomerId = data.customer;
  stripeSubscriptionId = data.subscription;
  status = 'active';
  // Plan will be set after fetching subscription details
}

if (eventType === 'customer.subscription.updated' || eventType === 'customer.subscription.created') {
  stripeCustomerId = data.customer;
  stripeSubscriptionId = data.id;
  stripePriceId = data.items?.data?.[0]?.price?.id;
  billingCycle = data.items?.data?.[0]?.plan?.interval === 'year' ? 'yearly' : 'monthly';
  currentPeriodStart = new Date(data.current_period_start * 1000).toISOString();
  currentPeriodEnd = new Date(data.current_period_end * 1000).toISOString();

  // Map Stripe status to our status
  const stripeStatus = data.status;
  if (stripeStatus === 'active') status = 'active';
  else if (stripeStatus === 'trialing') status = 'trialing';
  else if (stripeStatus === 'past_due') status = 'past_due';
  else if (stripeStatus === 'canceled') status = 'canceled';
  else status = 'active';

  // Map price ID to plan_id using env vars
  const soloPrices = [
    $env.STRIPE_PRICE_SOLO_MONTHLY,
    $env.STRIPE_PRICE_SOLO_YEARLY,
  ].filter(Boolean);
  const proPrices = [
    $env.STRIPE_PRICE_PRO_MONTHLY,
    $env.STRIPE_PRICE_PRO_YEARLY,
  ].filter(Boolean);

  if (soloPrices.includes(stripePriceId)) planId = 'solo';
  else if (proPrices.includes(stripePriceId)) planId = 'pro';
  else planId = 'solo'; // fallback
}

if (eventType === 'customer.subscription.deleted') {
  stripeCustomerId = data.customer;
  stripeSubscriptionId = data.id;
  status = 'canceled';
  planId = 'free';
}

if (eventType === 'invoice.payment_failed') {
  stripeCustomerId = data.customer;
  stripeSubscriptionId = data.subscription;
  status = 'past_due';
}

return [{ json: {
  eventType,
  organizationId,
  stripeCustomerId,
  stripeSubscriptionId,
  stripePriceId,
  status,
  billingCycle,
  currentPeriodStart,
  currentPeriodEnd,
  planId,
} }];

// Try to get org_id from the event directly (checkout.session.completed)
// or from the Supabase lookup (subscription events)
const eventData = $('Code - Parse Stripe Event').first().json;
const supabaseRows = $input.all();

const organizationId = eventData.organizationId ?? supabaseRows[0]?.json?.organization_id;

if (!organizationId) throw new Error('Could not resolve organization_id for customer: ' + eventData.stripeCustomerId);

return [{ json: { ...eventData, organizationId } }];

const eventData = $('Code - Resolve Organization ID').first().json;
const stripeSubscription = $input.first().json;

const stripePriceId = stripeSubscription.items?.data?.[0]?.price?.id;
const interval = stripeSubscription.items?.data?.[0]?.plan?.interval;
const billingCycle = interval === 'year' ? 'yearly' : 'monthly';
const currentPeriodStart = new Date(stripeSubscription.current_period_start * 1000).toISOString();
const currentPeriodEnd = new Date(stripeSubscription.current_period_end * 1000).toISOString();

// Map price to plan_id
const soloPrices = [$env.STRIPE_PRICE_SOLO_MONTHLY, $env.STRIPE_PRICE_SOLO_YEARLY].filter(Boolean);
const proPrices = [$env.STRIPE_PRICE_PRO_MONTHLY, $env.STRIPE_PRICE_PRO_YEARLY].filter(Boolean);

let planId = 'solo';
if (soloPrices.includes(stripePriceId)) planId = 'solo';
else if (proPrices.includes(stripePriceId)) planId = 'pro';

const updatePayload = {
  stripe_customer_id: eventData.stripeCustomerId,
  stripe_subscription_id: eventData.stripeSubscriptionId,
  stripe_price_id: stripePriceId,
  plan_id: planId,
  status: 'active',
  billing_cycle: billingCycle,
  current_period_start: currentPeriodStart,
  current_period_end: currentPeriodEnd,
  trial_ends_at: null,
};

return [{ json: { organizationId: eventData.organizationId, updatePayload } }];

const data = $input.first().json;

const updatePayload = {
  stripe_subscription_id: data.stripeSubscriptionId,
  stripe_price_id: data.stripePriceId,
  plan_id: data.planId,
  status: data.status,
  billing_cycle: data.billingCycle,
  current_period_start: data.currentPeriodStart,
  current_period_end: data.currentPeriodEnd,
};

// Remove null values
Object.keys(updatePayload).forEach(k => {
  if (updatePayload[k] === null || updatePayload[k] === undefined) delete updatePayload[k];
});

return [{ json: { organizationId: data.organizationId, updatePayload } }];
